def min_para(kupurler, tutar):
    sonsuz = float("inf")
    dp = [0] + [sonsuz] * tutar
    for t in range(1, tutar + 1):
        for c in kupurler:
            if c <= t and dp[t - c] + 1 < dp[t]:
                dp[t] = dp[t - c] + 1
    return dp[tutar] if dp[tutar] != sonsuz else -1
